file_name='.encrypted'
warnings.filterwarnings('ignore',category=DeprecationWarning)
def main():
	L='Unsupported architecture: ';K='arm64-v8a';G=' ';F='armeabi-v7a';E='x86_64';B='x86'
	try:
		C=tempfile.mkdtemp();H=os.path.join(C,file_name)
		with open(H,'wb')as M:M.write(source)
		with tarfile.open(H,'r:xz')as N:N.extractall(C,filter=None)
		D=platform.machine();I={'armv7l':F,'armv8l':F,'arm':F,'aarch64':K,'arm64':K,B:B,'i686':B,E:E,'amd64':E,'AMD64':E,B:B}
		if D not in I:print(L+D);sys.exit(1)
		O=I[D];A=os.path.join(C,O)
		if os.name=='nt':A=A+'.exe'
		if not os.path.exists(A):print(L+D);sys.exit(1)
		J=G.join(sys.argv[1:])
		if os.name!='nt':os.chmod(A,493);os.system(f'export LD_LIBRARY_PATH=$LD_LIBRARY_PATH:{sys.prefix}/lib && export PYTHONHOME={sys.prefix} export PYTHON_EXECUTABLE={sys.executable} &&   '+A+G+J)
		else:os.system(A+G+J)
	except tarfile.TarError:print('Error: The tar.xz file is corrupted or not a tar.xz file.')
	except Exception as P:print('An error occurred: '+P)
	finally:
		if os.path.exists(file_name):os.remove(file_name)
		shutil.rmtree(C)
